                            </template>
                        </template>
                        
                    </template>
                </v-list>
            </v-card>

            <v-divider class="mb-3"></v-divider>

            <div class="text-subtitle-1 font-weight-bold text-error mb-1">Monster Debuff Coverage</div>
            <div class="text-caption text-grey mb-4">
                Target: {{ targetId ? (prettyEntityName(entityMap[targetId]?.actor) || targetId) : 'All Enemies' }}
            </div>
            
            <v-row no-gutters class="overflow-y-auto align-content-start">
                <v-col cols="12" v-for="status in globalMonsterCoverage" :key="status.ccId" class="mb-2">
                    <v-tooltip bottom>
                        <template v-slot:activator="{ props }">
                            <v-chip v-bind="props" size="small" color="error" variant="outlined" class="w-100 justify-start">
