        </v-col>

        <v-col cols="12" md="9" class="pa-2">
            <v-sheet class="mb-4">
                <div ref="chartDom" style="width: 100%; min-height: 300px;"></div>
            </v-sheet>

            <v-row no-gutters class="mb-4">
                <v-col cols="12" md="3" class="pr-2 mb-2">
                    <v-select
                        v-model="dpsWindow"
