                <v-col cols="12" md="5" class="mb-2">
                    <v-select
                        v-model="selectedGanttMonsterStatuses"
                        :items="ganttMonsterStatusOptions"
                        label="Gantt Monster Debuffs"
                        multiple
                        chips
                        closable-chips
                        variant="outlined"
                        density="compact"
                        hide-details
                    ></v-select>
                </v-col>
            </v-row>

            <v-expansion-panels multiple v-for="v in pcEntities" v-bind:key="v.actor.id">
                <template v-if="v.totalDamage > 0">
                    <v-expansion-panel>
                        <v-expansion-panel-title>
                            <v-row no-gutters align="center">
                                <v-col cols="12" class="mb-1">
                                    <strong>{{ prettyEntityName(v.actor) }}</strong> 
                                    <span class="ml-2">
                                        {{ v.totalDamage.toFixed(0) }} | {{ (100 * v.totalDamage / allApplyDamage).toFixed(1) }}% | dps {{ v.damages.length < 2 ? 0 : Math.round(v.totalDamage / (v.damages[v.damages.length - 1].At - v.damages[0].At)) }} | critRate: {{ getCriticalRate(v.damages) }}%
                                    </span>
                                </v-col>
                                <v-col cols="12" class="d-flex flex-wrap align-center mt-1">
                                    <span class="text-caption text-success mr-2">Overall Buffs:</span>
                                    <template v-for="status in getStatusCoverage(v.damages).playerBuffs" :key="'p_all_'+status.ccId">
                                        <v-tooltip bottom>
                                            <template v-slot:activator="{ props }">
                                                <v-chip v-bind="props" size="x-small" color="success" variant="outlined" class="mr-1 mb-1">
                                                    <img :src="`https://mabires.pril.cc/characterconditionimage/${region}/${status.ccId}/${status.ccId}.png`" 
                                                         width="14" height="14" class="mr-1" />
                                                    {{ status.percentage }}%
                                                </v-chip>
                                            </template>
                                            <span>{{ status.name }}</span>
                                        </v-tooltip>
                                    </template>
                                </v-col>
                            </v-row>
                        </v-expansion-panel-title>

                        <v-expansion-panel-text class="pa-3">
                            <v-sheet
                                v-for="[skillId, damageBySkill] in Object.entries(v.groupedTotalDamages).sort(([, av], [_, bv]) => bv - av)"
                                v-bind:key="skillId" class="d-flex">
                                <v-sheet width="32" class="mr-2">
                                    <img width="32" height="32" :src='`https://mabires.pril.cc/skillimage/${region}/${skillId}/${skillId}.png`' />
                                </v-sheet>
                                <v-sheet width="100%" class="mb-4">
                                    <v-sheet width="100%"
                                        @click.stop="showEntityDetailDamageList(v.actor.id, targetId, +skillId)">
                                        {{ skillNameMap[+skillId] || `unknownSkill:${skillId}` }}
                                        damage: {{ damageBySkill.toFixed(0) }}
                                        count: {{ v.groupedCount[+skillId] }}
                                        avgDamage: {{ (v.groupedCount[+skillId] ? damageBySkill / v.groupedCount[+skillId] : 0).toFixed(0) }}
                                        minDamage: {{ v.groupedMinDamages[+skillId]?.toFixed(0) || '0' }}
                                        maxDamage: {{ v.groupedMaxDamages[+skillId]?.toFixed(0) || '0' }}
                                        critRate: {{ getCriticalRate(v.groupedDamages[+skillId] || []) }}%
                                        damage %: {{ (100 * damageBySkill / v.totalDamage).toFixed(1) }}%
                                    </v-sheet>

                                    <div class="mt-1 mb-1">
                                        <div class="d-flex flex-wrap align-center mb-1" v-if="getStatusCoverage(v.groupedDamages[+skillId] || []).playerBuffs.length">
                                            <span class="text-caption text-success mr-2">Buffs:</span>
                                            <template v-for="status in getStatusCoverage(v.groupedDamages[+skillId] || []).playerBuffs" :key="'p_sk_'+status.ccId">
                                                <v-chip size="x-small" color="success" variant="outlined" class="mr-1 mb-1 px-1">
                                                    <img :src="`https://mabires.pril.cc/characterconditionimage/${region}/${status.ccId}/${status.ccId}.png`" width="12" height="12" class="mr-1" />
                                                    {{ status.percentage }}%
                                                </v-chip>
                                            </template>
                                        </div>

                                        <div class="d-flex flex-wrap align-center" v-if="getStatusCoverage(v.groupedDamages[+skillId] || []).monsterDebuffs.length">
                                            <span class="text-caption text-error mr-2">Debuffs:</span>
                                            <template v-for="status in getStatusCoverage(v.groupedDamages[+skillId] || []).monsterDebuffs" :key="'m_sk_'+status.ccId">
                                                <v-chip size="x-small" color="error" variant="outlined" class="mr-1 mb-1 px-1">
                                                    <img :src="`https://mabires.pril.cc/characterconditionimage/${region}/${status.ccId}/${status.ccId}.png`" width="12" height="12" class="mr-1" />
                                                    {{ status.percentage }}%
                                                </v-chip>
                                            </template>
                                        </div>
                                    </div>

                                    <v-sheet width="100%" height="16">
                                        <v-sheet @click.stop="showEntityDetailDamageList(v.actor.id, '', +skillId)"
                                            :color="getMabiNameColor(skillNameMap[+skillId] || `unknownSkill:${skillId}`)"
                                            height="100%"
                                            :width="`${Math.round(100 * damageBySkill / v.totalDamage).toFixed(0)}%`"
                                            class="rounded-xl">
                                        </v-sheet>
                                    </v-sheet>
                                </v-sheet>
                            </v-sheet>
                        </v-expansion-panel-text>
                    </v-expansion-panel>
                    <v-sheet width="100%" height="16" class="mb-2">
                        <v-sheet :color="getMabiNameColor(prettyEntityName(v.actor)!)" height="100%"
                            :width="`${Math.round(100 * v.totalDamage / allApplyDamage).toFixed(0)}%`" class="rounded-xl">
                        </v-sheet>
                    </v-sheet>
                </template>
            </v-expansion-panels>
        </v-col>
    </v-row>

    <v-dialog v-model="detailDialog" min-width="60vw" height="90svh">
        <v-card>
            <v-card-text class="pa-0">
                <damage-list :attacker-name="detailDialogData?.attackerName || ''"
                :target-name="detailDialogData?.skillName || ''" :damages="detailDialogData?.damages || []" />
            </v-card-text>
            <v-card-actions>
                <v-btn color="primary" block @click="detailDialog = false">Close</v-btn>
            </v-card-actions>
        </v-card>
    </v-dialog>
</template>

<script lang="ts">
import { defineComponent, inject, ref, computed, onUnmounted, watch, onMounted } from "vue";
import highcharts, { Options, SeriesAreaOptions } from 'highcharts';
import HighchartsXrange from 'highcharts/modules/xrange';
if (typeof HighchartsXrange === 'function') {
    HighchartsXrange(highcharts);
}

import { getMabiNameColor } from '@/util';
import { EntityDamage, ActorManager, BaseActor, GroupActor, EntityActor } from '@/eventActor';
import { DamageCollectorBase, DualGroupedDamageCollector, GroupedDamageCollector } from '@/actionCollector';

import DamageList from '@/components/subComponents/damageList.vue';

export default defineComponent({
    components: {
        DamageList,
    },
    setup() {
        const isLoading = inject('isLoading');
        const region = inject('region');
        const raceNameMap = inject('raceNameMap');
        const skillNameMap = inject('skillNameMap');
        const appEvent = inject('appEvent');
        const actorManager = inject('actorManager');
        const dcManager = inject('dcManager');

        // add this aline
        const condNameMap = inject('condNameMap') as any;

        const damageCollectorMap: Record<string, DamageCollectorBase> = {};
        const chartDom = ref<HTMLElement>(undefined!);
        let chart: Highcharts.Chart = undefined!;

        const chartData = computed(() => getChartSeriesData(pcEntities.value.filter(v => v.totalDamage > 10000)));

        const formatTime = (unixSeconds: number) => {
            if (unixSeconds === 0 || unixSeconds === Infinity) return '';
            const d = new Date(unixSeconds * 1000);
            return d.toLocaleTimeString([], { hour12: false }); 
        };

        // NEW: Formats raw seconds into 'Xm Ys'
        const formatDuration = (seconds: number) => {
            if (seconds === 0) return '0s';
            const m = Math.floor(seconds / 60);
            const s = Math.floor(seconds % 60);
            return m > 0 ? `${m}m ${s}s` : `${s}s`;
        };

        onUnmounted(() => {
            appEvent.value.removeEventListener('clear', clearTarget);

            for (const v of Object.values(damageCollectorMap)) {
                dcManager.value.removeDamageCollector(v);
            }
        });


        const trackedPlayerBuffs = new Set([
            680, 192, 887, 10048, 10034, 10038, 800, 63, 1033, 511, 717, 914,
            1045, 1122, 1016, 1037, 577, 1035, 407, 406, 476, 1036, 1023, 915, 934
        ]); 
        
        const trackedMonsterDebuffs = new Set([
            1164, 1165, 1166, 1063, 1093, 1094, 511, 1011, 1138, 
            598, 1026, 1004, 578, 464, 913, 803, 716, 10001, 10002
        ]);

        const statusAliasMap: Record<number, number> = {
            912: 913, // Treats 912 as if it were 913
            504: 392  // Treats 504 as if it were 392
        };

        const resolveCCId = (id: number) => statusAliasMap[id] || id;

        // ==========================================
        // 1. GLOBAL MONSTER COVERAGE (LEFT PANEL)
        // Aggregates hits against the target across ALL players
        // ==========================================
        const globalMonsterCoverage = computed(() => {
            let totalHits = 0;
            const monsterStatusCounts: Record<number, number> = {};

            pcEntities.value.forEach(v => {
                const damages = v.damages || [];
                totalHits += damages.length;

                damages.forEach(dmg => {
                    const debuffsThisHit = new Set(
                        (dmg.TargetConditions || [])
                            .map(c => resolveCCId(c.CCId)) // <--- ADD resolveCCId HERE
                            .filter(id => trackedMonsterDebuffs.has(id))
                    );

                    debuffsThisHit.forEach(ccId => {
                        monsterStatusCounts[ccId] = (monsterStatusCounts[ccId] || 0) + 1;
                    });
                });
            });

            if (totalHits === 0) return [];

            return Object.entries(monsterStatusCounts)
                .map(([ccIdStr, count]) => {
                    const ccId = Number(ccIdStr);
                    return {
                        ccId: ccId,
                        name: condNameMap.value[ccId] || `Unknown:${ccId}`,
                        percentage: ((count / totalHits) * 100).toFixed(1)
                    };
                })
                .sort((a, b) => Number(b.percentage) - Number(a.percentage));
        });

        // ==========================================
        // 2 & 3. PLAYER AND SKILL COVERAGE
        // Can be used for overall player (v.damages) or specific skill (v.groupedDamages)
        // ==========================================
        const getStatusCoverage = (damages: EntityDamage[]) => {
            const totalHits = damages?.length || 0;
            if (totalHits === 0) return { playerBuffs: [], monsterDebuffs: [] };

            const playerStatusCounts: Record<number, number> = {};
            const monsterStatusCounts: Record<number, number> = {};

            damages.forEach(dmg => {
                const playerBuffsThisHit = new Set(
                    (dmg.Conditions || [])
                        .map(c => resolveCCId(c.CCId)) // <--- ADD resolveCCId HERE
                        .filter(id => trackedPlayerBuffs.has(id))
                );
                
                const monsterDebuffsThisHit = new Set(
                    (dmg.TargetConditions || [])
                        .map(c => resolveCCId(c.CCId)) // <--- ADD resolveCCId HERE
                        .filter(id => trackedMonsterDebuffs.has(id))
                );

                playerBuffsThisHit.forEach(ccId => {
                    playerStatusCounts[ccId] = (playerStatusCounts[ccId] || 0) + 1;
                });
                monsterDebuffsThisHit.forEach(ccId => {
                    monsterStatusCounts[ccId] = (monsterStatusCounts[ccId] || 0) + 1;
                });
            });

            const formatCoverage = (counts: Record<number, number>) => {
                return Object.entries(counts)
                    .map(([ccIdStr, count]) => {
                        const ccId = Number(ccIdStr);
                        return {
                            ccId: ccId,
                            name: condNameMap.value[ccId] || `Unknown:${ccId}`,
                            percentage: ((count / totalHits) * 100).toFixed(1)
                        };
                    })
                    .sort((a, b) => Number(b.percentage) - Number(a.percentage));
            };

            return {
                playerBuffs: formatCoverage(playerStatusCounts),
                monsterDebuffs: formatCoverage(monsterStatusCounts)
            };
        };

        const getCriticalRate = (damages: EntityDamage[]) => {
            const totalHits = damages?.length || 0;
            if (totalHits === 0) return "0.0";

            let critCount = 0;
            
            damages.forEach(dmg => {
                const d = dmg as any;
                // Mabinogi combat packets use "Option" as a bitmask where 1 = Critical.
                // Depending on how the Go backend parses it, it might also be a boolean.
                // This checks all common naming conventions to be perfectly safe!
                if ((d.Option !== undefined && (d.Option & 1)) || d.IsCritical || d.isCritical || d.Critical) {
                    critCount++;
                }
            });

            return ((critCount / totalHits) * 100).toFixed(1);
        };

        const getDC = (attackerId: string) => {
            const key = `${attackerId}`;
            if (damageCollectorMap[key]) {
                return damageCollectorMap[key] as DualGroupedDamageCollector;
            }

            const dc = dcManager.value.getDualGroupedDamageCollector(v => v.Id == attackerId, v => v.TargetId, v => `${v.SkillId}`);
            damageCollectorMap[key] = dc;

            return dc;
        }

        const getTargetDC = () => {
            const key = `target`;
            if (damageCollectorMap[key]) {
                return damageCollectorMap[key] as GroupedDamageCollector;
            }

            const dc = dcManager.value.getGroupedDamageCollector(() => true, v => v.TargetId);
            damageCollectorMap[key] = dc;

            return dc;
        }
        const targetDC = ref(getTargetDC());

        const showEntityDetailDamageList = (attackerId: string, targetId: string, skillId: number) => {
            const entity = entityMap.value[attackerId];
            if (!entity) {
                return;
            }

            const damages = targetId ?
                entity.dc.dualGroupedDamages[targetId][skillId] :
                entity.dc.grouped2Damages[skillId];

            detailDialog.value = true;
            detailDialogData.value = {
                attackerName: prettyEntityName(entity.actor)!,
                skillName: skillNameMap.value[skillId] || `unknownSkill:${skillId}`,
                damages: damages,
            };
        }

        const entityMap = computed(() => {
            const m: Record<string, { actor: EntityActor, dc: DualGroupedDamageCollector }> = {};

            for (const k in actorManager.value.entityMap) {
                const v = actorManager.value.entityMap[k];

                m[k] = {
                    actor: v,
                    dc: getDC(k),
                }
            }

            return m;
        });

        const entityMapWithTargetData = computed(() => {
            const m: Record<string, EntityExtended> = {};

            for (const k in entityMap.value) {
                const v = entityMap.value[k];

                const totalDamage = targetId.value ? v.dc.groupedTotalDamages[targetId.value] || 0 : v.dc.totalDamage;
                const damages = targetId.value ? v.dc.groupedDamages[targetId.value] || [] : v.dc.damages;
                const groupedTotalDamages = targetId.value ? v.dc.dualGroupedTotalDamages[targetId.value] : v.dc.grouped2TotalDamages;
                const groupedDamages = targetId.value ? v.dc.dualGroupedDamages[targetId.value] : v.dc.grouped2Damages;
                const groupedMinDamages = targetId.value ? v.dc.dualGroupedMinDamages[targetId.value] : v.dc.grouped2MinDamages;
                const groupedMaxDamages = targetId.value ? v.dc.dualGroupedMaxDamages[targetId.value] : v.dc.grouped2MaxDamages;
                const groupedCount = targetId.value ? v.dc.dualGroupedCount[targetId.value] : v.dc.grouped2Count;

                m[k] = {
                    ...v,
                    totalDamage,
                    damages,
                    groupedTotalDamages,
                    groupedDamages,
                    groupedMinDamages,
                    groupedMaxDamages,
                    groupedCount,
                }
            }

            return m;
        })

        const pcEntities = computed(() =>
            Object.values(entityMapWithTargetData.value).filter(v => v.actor.isPC).sort((a, b) => b.totalDamage - a.totalDamage));

        const targetId = ref('');

        const ganttCategories = ref<string[]>([]);

        const clearTarget = () => {
            targetId.value = '';
        }

        onMounted(() => {
            appEvent.value.addEventListener('clear', clearTarget);

            // ==========================================
            // DYNAMIC CHART HEIGHT CALCULATOR
            // ==========================================
            const getDynamicLayout = () => {
                const rowCount = ganttCategories.value.length || 1;
                const rowHeight = 35; // Increased to 35 for better label clearance
                const ganttHeight = rowCount * rowHeight; 
                const dpsHeight = 300; 
                
                // Total height MUST include 200px of bottom padding for the legend
                const totalHeight = dpsHeight + ganttHeight + 200; 

                return {
                    chartHeight: totalHeight,
                    yAxis: [
                        { 
                            title: { text: 'DPS' }, 
                            min: 0, 
                            height: dpsHeight, 
                            lineWidth: 1,
                            labels: {
                                style: { color: '#e0e0e0' }
                            }
                        },
                        { 
                            title: { text: 'Key Statuses' }, 
                            top: dpsHeight + 60, // Clean gap between charts
                            height: ganttHeight, 
                            offset: 0, 
                            lineWidth: 1, 
                            categories: ganttCategories.value, 
                            reversed: true,
                            tickInterval: 1, // FORCE every label to render
                            labels: {
                                step: 1, // Prevent Highcharts from hiding labels
                                style: { fontSize: '11px' , color: '#e0e0e0'}
                            }
                        }
                    ]
                };
            };

            let debounced1 = 0;
            watch(entityMap, () => {
                if (debounced1) return;

                setTimeout(() => {
                    debounced1 = 0;
                    if (chart) chart.destroy();
                    
                    const layout = getDynamicLayout();
                    
                    // Force the physical HTML div to resize so it doesn't clip the chart
                    if (chartDom.value) {
                        chartDom.value.style.height = `${layout.chartHeight}px`;
                    }
                    
                    chartOpt.chart = { ...chartOpt.chart, height: layout.chartHeight };
                    
                    chart = highcharts.chart(chartDom.value, { 
                        ...chartOpt, 
                        yAxis: layout.yAxis, 
                        series: chartData.value 
                    } as any);
                }, 100);
            });

            let debounced2: number = 0;
            watch(chartData, () => {
                if (debounced2) return;

                debounced2 = setTimeout(() => {
                    debounced2 = 0;
                    if (!chart) return;
                    
                    const layout = getDynamicLayout();
                    
                    // Force the physical HTML div to resize
                    if (chartDom.value) {
                        chartDom.value.style.height = `${layout.chartHeight}px`;
                    }

                    // Tell Highcharts to resize its internal SVG container
                    chart.setSize(undefined, layout.chartHeight, false); 
                    
                    // Update the axes with redraw enabled
                    chart.update({ 
                        yAxis: layout.yAxis,
                        series: chartData.value 
                    } as any, true, true); 
                }, 100);
            });
        })

        const allApplyDamage = computed(() =>
            pcEntities.value.reduce((acc, v) => acc + v.totalDamage, 0));

        const detailDialog = ref(false);
        const detailDialogData = ref<{ attackerName: string; skillName: string; damages: EntityDamage[] }>();

        const prettyEntityName = (entity?: BaseActor) => {
            if (!entity) {
                return undefined;
            }

            if (ActorManager.pcRaceSet.has(entity.raceId)) {
                return entity.name;
            }

            const raceName = raceNameMap.value[entity.raceId] || `unknownRace:${entity.raceId}`;
            if (entity instanceof GroupActor) {
                return raceName;
            }

            // for monster
            if (entity.name[0] >= '0' && entity.name[0] <= '9') {
                return `${raceName} (${entity.name.slice(-4)})`;
            }

            // for pet
            return entity.name;
        }
        
        const sortedTargetList = computed(() => {
            // Define the specific Mabinogi Race IDs
            const bossRaceIds = new Set([7600, 7601, 7602, 7603]);
            const summonRaceIds = new Set([7604, 7605, 7606, 7607, 7608, 7609, 7610, 7611, 7612, 7613, 7614]);

            // 1. Create a flat, chronologically sorted list of all valid monsters
            const flatList = Object.entries(targetDC.value.groupedDamages)
                .filter(([id]) => {
                    const actor = actorManager.value.entityMap[id];
                    if (!actor) return true; 
                    if (actor.isPC) return false; 
                    if (actor instanceof GroupActor) return true; 
                    if (actor.name && actor.name[0] >= '0' && actor.name[0] <= '9') return true; 
                    return false; 
                })
                .map(([id, damages]) => {
                    // Safely find the absolute first and last hit times
                    let firstHitTime = Infinity;
                    let lastHitTime = -Infinity;
                    
                    damages.forEach(d => {
                        if (d.At < firstHitTime) firstHitTime = d.At;
                        if (d.At > lastHitTime) lastHitTime = d.At;
                    });

                    const totalDmg = targetDC.value.groupedTotalDamages[id] || 0;
                    
                    // Calculate duration (Difference between first and last hit)
                    const duration = (firstHitTime !== Infinity && lastHitTime !== -Infinity) 
                        ? Math.max(0, lastHitTime - firstHitTime) 
                        : 0;
                    
                    const actor = actorManager.value.entityMap[id];
                    const name = actor ? prettyEntityName(actor) : id;
                    const raceId = actor ? actor.raceId : 0; 

                    return {
                        id,
                        totalDmg,
                        firstHitTime,
                        duration, // NEW: Export the duration
                        name: name || id,
                        raceId,
                        children: [] as any[] 
                    };
                }).sort((a, b) => a.firstHitTime - b.firstHitTime);

            // 2. Group the summoned monsters under the latest boss
            const groupedList: any[] = [];
            let currentBoss: any = null;

            for (const item of flatList) {
                if (bossRaceIds.has(item.raceId)) {
                    currentBoss = item;
                    groupedList.push(item);
                } else if (summonRaceIds.has(item.raceId) && currentBoss) {
                    currentBoss.children.push(item);
                } else {
                    groupedList.push(item);
                }
            }

            // NEW: 2.5 Extract Boss 7603's children and sub-group them!
            const mechanicRaceIds = new Set([7604, 7605, 7606, 7607, 7608]);
            for (const boss of groupedList) {
                if (boss.raceId === 7603 && boss.children && boss.children.length > 0) {
                    const mechanics: any[] = [];
                    const others: any[] = [];

                    boss.children.forEach((child: any) => {
                        if (mechanicRaceIds.has(child.raceId)) {
                            child.numericId = parseInt(child.id, 10) || 0;
                            mechanics.push(child);
                        } else {
                            others.push(child);
                        }
                    });

                    // Sort strictly by server spawn order
                    mechanics.sort((a, b) => a.numericId - b.numericId);

                    // 1. Cluster simultaneous spawns (and their replacements) using a gap of 200
                    const clusters: any[][] = [];
                    let currentCluster: any[] = [];

                    mechanics.forEach(mech => {
                        if (currentCluster.length === 0) {
                            currentCluster.push(mech);
                        } else {
                            const lastMech = currentCluster[currentCluster.length - 1];
                            if (mech.numericId - lastMech.numericId <= 200) {
                                currentCluster.push(mech);
                            } else {
                                clusters.push(currentCluster);
                                currentCluster = [mech];
                            }
                        }
                    });
                    if (currentCluster.length > 0) clusters.push(currentCluster);

                    // 2. Identify the mechanic of each cluster based on Max HP
                    let seen60Mech = false;
                    const newChildren: any[] = [];

                    clusters.forEach((cluster, idx) => {
                        // Find the highest damage taken by any single monster in this cluster
                        const maxDmg = Math.max(...cluster.map(m => m.totalDmg));
                        
                        let config: any = null;

                        if (maxDmg >= 63000000) {
                            // Has a 65M HP monster -> Must be 60% Mechanic
                            config = { name: '60% Mechanic', targetKills: 3, hpThreshold: 63000000 };
                            seen60Mech = true; 
                        } else if (maxDmg >= 37000000) {
                            // Has a 38M HP monster -> Check state to see if it's 80% or 40%
                            if (!seen60Mech) {
                                config = { name: '80% Mechanic', targetKills: 3, hpThreshold: 37000000 };
                            } else {
                                config = { name: '40% Mechanic', targetKills: 5, hpThreshold: 37000000 };
                            }
                        }

                        let waveTotalDmg = 0;
                        let waveFirstHit = Infinity;
                        let waveLastHit = -Infinity;
                        let clearedCount = 0;

                        cluster.forEach(m => {
                            waveTotalDmg += m.totalDmg;
                            if (m.firstHitTime < waveFirstHit) waveFirstHit = m.firstHitTime;
                            if (m.firstHitTime + m.duration > waveLastHit) waveLastHit = m.firstHitTime + m.duration;
                            
                            // Count how many reached the kill threshold for this specific mechanic
                            if (config && m.totalDmg >= config.hpThreshold) {
                                clearedCount++;
                            }
                        });

                        const duration = (waveFirstHit !== Infinity && waveLastHit !== -Infinity) 
                            ? Math.max(0, waveLastHit - waveFirstHit) : 0;

                        if (config) {
                            // We positively identified a mechanic wave
                            newChildren.push({
                                id: `mech_group_${boss.id}_${idx}`,
                                name: `${config.name} (Cleared: ${clearedCount} / ${config.targetKills})`,
                                totalDmg: waveTotalDmg,
                                firstHitTime: waveFirstHit === Infinity ? 0 : waveFirstHit,
                                duration: duration,
                                children: cluster
                            });
                        } else {
                            // Max damage didn't hit 37M, meaning it's a general skill summon (like 3695)
                            newChildren.push({
                                id: `normal_summons_${boss.id}_${idx}`,
                                name: `Normal Boss Summons`,
                                totalDmg: waveTotalDmg,
                                firstHitTime: waveFirstHit === Infinity ? 0 : waveFirstHit,
                                duration: duration,
                                children: cluster
                            });
                        }
                    });

                    // Put any leftover non-mechanic race IDs into a collapsed tab
                    if (others.length > 0) {
                        let othersTotalDmg = 0;
                        others.forEach(o => othersTotalDmg += o.totalDmg);
                        newChildren.push({
                            id: `mech_group_${boss.id}_others`,
                            name: 'Other Summons',
                            totalDmg: othersTotalDmg,
                            firstHitTime: others[0]?.firstHitTime || 0,
                            duration: 0, 
                            children: others
                        });
                    }

                    // Replace the boss's original flat list with the newly identified groups
                    boss.children = newChildren;
                }
            }

            // 3. Prepend the "All Enemies" option at the very top
            groupedList.unshift({
                id: '',
                totalDmg: targetDC.value.totalDamage,
                firstHitTime: 0,
                name: 'All Enemies',
                raceId: 0,
                children: []
            });

            return groupedList;
        });

        const expandedBosses = ref<Set<string>>(new Set());
        const toggleBoss = (id: string) => {
            const newSet = new Set(expandedBosses.value);
            if (newSet.has(id)) {
                newSet.delete(id);
            } else {
                newSet.add(id);
            }
            expandedBosses.value = newSet;
        };

        const hiddenPlayers = ref<Set<string>>(new Set());

        const dpsWindow = ref(10); // Default to 5 seconds
        const dpsWindowOptions = [
            { title: '1s Window', value: 1 },
            { title: '5s Window', value: 5 },
            { title: '10s Window', value: 10 },
            { title: '15s Window', value: 15 },
            { title: '20s Window', value: 20 }
        ];
        
        const selectedGanttPlayerStatuses = ref<number[]>([1037]); // Default to 1037
        const selectedGanttMonsterStatuses = ref<number[]>([803]); // Default to 803

        const ganttPlayerStatusOptions = computed(() => {
            return Array.from(trackedPlayerBuffs).map(id => ({
                title: condNameMap.value[id] ? `${condNameMap.value[id]} (${id})` : `Unknown:${id}`,
                value: id
            }));
        });

        const ganttMonsterStatusOptions = computed(() => {
            return Array.from(trackedMonsterDebuffs).map(id => ({
                title: condNameMap.value[id] ? `${condNameMap.value[id]} (${id})` : `Unknown:${id}`,
                value: id
            }));
        });

        const getGanttTimeframes = (damages: EntityDamage[], ccId: number, isTarget: boolean, yIndex: number, baseTime: number) => {
            const sorted = [...damages].sort((a, b) => a.At - b.At);
            const timeframes: any[] = [];
            let currentStart = -1;
            let currentEnd = -1;
            const gapLimit = 10; 

            sorted.forEach(dmg => {
                const conditions = isTarget ? dmg.TargetConditions : dmg.Conditions;
                
                const hasStatus = conditions?.some(c => resolveCCId(c.CCId) === ccId);

                // NEW: Subtract baseTime so it aligns with the 0-minute mark!
                const timeMs = (dmg.At * 1000) - baseTime;

                if (hasStatus) {
                    if (currentStart === -1) {
                        currentStart = timeMs;
                        currentEnd = timeMs;
                    } else if ((timeMs - currentEnd) <= gapLimit * 1000) {
                        // Buff is still active, extend the end time
                        currentEnd = timeMs;
                    } else {
                        // Gap exceeded limit, close out the previous bar and start a new one
                        // We use Math.max to give 1-hit buffs a minimum visual width of 3 seconds
                        timeframes.push({ x: currentStart, x2: Math.max(currentEnd, currentStart + 3000), y: yIndex });
                        currentStart = timeMs;
                        currentEnd = timeMs;
                    }
                }
            });

            // Push the final bar if combat ended while buff was active
            if (currentStart !== -1) {
                timeframes.push({ x: currentStart, x2: Math.max(currentEnd, currentStart + 3000), y: yIndex });
            }

            return timeframes;
        };

        // Update the chart series calculator to use dpsWindow.value
        const getChartSeriesData = (entity: EntityExtended[]): any[] => {
            if (!entity || entity.length === 0) return [];

            const win = dpsWindow.value; 
            let globalMinTime = Infinity;
            let globalMaxTime = -Infinity;

            entity.forEach(v => {
                v.damages.forEach(dmg => {
                    const bucketTime = (dmg.At - (dmg.At % win)) * 1000; 
                    if (bucketTime < globalMinTime) globalMinTime = bucketTime;
                    if (bucketTime > globalMaxTime) globalMaxTime = bucketTime;
                });
            });

            if (globalMinTime === Infinity) return [];
            // Set our zero-point anchor
            const baseTime = globalMinTime;

            const series: any[] = [];
            const newCategories: string[] = [];
            let yIndex = 0;
            const allDamages: EntityDamage[] = [];

            // ==========================================
            // NEW: Custom Dark-Mode Optimized Palette
            // ==========================================
            const chartPalette = [
                '#5c6bc0', // Muted Indigo
                '#66bb6a', // Soft Green
                '#ef5350', // Soft Red
                '#ab47bc', // Muted Purple
                '#ffa726', // Muted Orange
                '#26c6da', // Soft Cyan
                '#d4e157', // Muted Lime
                '#ec407a', // Soft Pink
                '#8d6e63', // Soft Brown
                '#78909c', // Blue Grey
                '#ffca28', // Amber
                '#26a69a'  // Teal
            ];

            // 1. Plot DPS and Player Statuses (Grouped by Player)
            entity.forEach((v, playerIndex) => {
                if (v.damages) allDamages.push(...v.damages);
                
                const playerName = prettyEntityName(v.actor) || 'Unknown';
                const playerId = `dps_line_${playerIndex}`;
                
                // NEW: Grab a distinct color from our palette instead of using the random hash
                const playerColor = chartPalette[playerIndex % chartPalette.length];
                
                const isHidden = hiddenPlayers.value.has(playerId); 

                // --- DPS Line ---
                const bucketMap = new Map<number, number>();
                v.damages.forEach(dmg => {
                    const bucketTime = (dmg.At - (dmg.At % win)) * 1000;
                    bucketMap.set(bucketTime, (bucketMap.get(bucketTime) || 0) + dmg.Damage);
                });

                const dpsData: [number, number][] = [];
                for (let t = globalMinTime; t <= globalMaxTime; t += (win * 1000)) {
                    const dmgInBucket = bucketMap.get(t) || 0;
                    dpsData.push([t - baseTime, Math.round(dmgInBucket / win)]);
                }

                series.push({
                    id: playerId,
                    type: 'spline',
                    yAxis: 0, 
                    name: playerName,
                    data: dpsData,
                    color: playerColor, // Applies the new custom color
                    visible: !isHidden, 
                    marker: { enabled: false },
                    events: {
                        legendItemClick: function () {
                            const newSet = new Set(hiddenPlayers.value);
                            if (newSet.has(playerId)) {
                                newSet.delete(playerId);
                            } else {
                                newSet.add(playerId);
                            }
                            hiddenPlayers.value = newSet;
                            return false; 
                        }
                    }
                });

                // --- Player Gantt Rows ---
                if (!isHidden) {
                    const playerGanttData: any[] = [];
                    for (const ccId of selectedGanttPlayerStatuses.value) {
                        const statusName = condNameMap.value[ccId] || String(ccId);
                        newCategories.push(`${playerName} (${statusName})`);

                        const timeframes = getGanttTimeframes(v.damages, ccId, false, yIndex, baseTime);
                        playerGanttData.push(...timeframes.map(pt => ({
                            ...pt,
                            color: playerColor // Applies the matching custom color to the Gantt bars
                        })));
                        
                        yIndex++; 
                    }

                    if (playerGanttData.length > 0) {
                        series.push({
                            id: `${playerId}_gantt`,
                            type: 'xrange',
                            yAxis: 1, 
                            data: playerGanttData,
                            showInLegend: false,
                            tooltip: { pointFormat: '<b>{point.category}</b> active' }
                        });
                    }
                }
            });

            // 2. Plot Global Monster Statuses
            const monsterGanttData: any[] = [];
            for (const ccId of selectedGanttMonsterStatuses.value) {
                const statusName = condNameMap.value[ccId] || String(ccId);
                newCategories.push(`Monster (${statusName})`);

                const timeframes = getGanttTimeframes(allDamages, ccId, true, yIndex, baseTime);
                monsterGanttData.push(...timeframes.map(mt => ({
                    ...mt,
                    color: '#ff9800' // Keeps the Monster Debuff a distinct, bright Orange
                })));
                
                yIndex++;
            }

            if (monsterGanttData.length > 0) {
                series.push({
                    id: 'global_monster_gantt',
                    type: 'xrange',
                    yAxis: 1, 
                    data: monsterGanttData,
                    showInLegend: false,
                    tooltip: { pointFormat: '<b>{point.category}</b> active' }
                });
            }

            ganttCategories.value = newCategories; 
            return series;
        };

        return {
            isLoading,
            region,

            chartDom,
            pcEntities,
            allApplyDamage,
            targetId,
            sortedTargetList,
            expandedBosses,
            toggleBoss,
            formatTime,
            detailDialog,
            detailDialogData,

            skillNameMap,
            entityMap: entityMapWithTargetData,

            showEntityDetailDamageList,
            getMabiNameColor,
            prettyEntityName,

            // add
            condNameMap,
            globalMonsterCoverage,
            getStatusCoverage,
            getCriticalRate,
            dpsWindow,
            dpsWindowOptions,

            selectedGanttPlayerStatuses,
            selectedGanttMonsterStatuses,
            ganttPlayerStatusOptions,
            ganttMonsterStatusOptions,

            formatDuration
        }
    }
});

type EntityExtended = {
    actor: EntityActor,
    dc: DualGroupedDamageCollector,
    totalDamage: number,
    damages: EntityDamage[],
    groupedTotalDamages: Record<string, number>,
    groupedDamages: Record<string, EntityDamage[]>,
    groupedMinDamages: Record<string, number>,
    groupedMaxDamages: Record<string, number>,
    groupedCount: Record<string, number>,
};

const chartOpt: Options = {
    // CRITICAL: Must be true so 0 milliseconds evaluates to 00:00:00
    time: { useUTC: true } as any, 
    lang: { locale: 'en' },
    title: { text: '' },
    chart: {
        zooming: { type: 'x' },
        backgroundColor: 'transparent'
    },
    xAxis: { 
        type: 'datetime',
        crosshair: true,
        labels: {
            style: { color: '#e0e0e0' },
            format: '{value:%M:%S}' // Format the X-axis labels as MM:SS
        }
    },
    legend: {
        itemStyle: { color: '#e0e0e0', fontWeight: 'normal' },
        itemHoverStyle: { color: '#ffffff' },
        itemHiddenStyle: { color: '#444444' }
    },
    tooltip: {
        shared: true,
        valueDecimals: 0,
        xDateFormat: '%M:%S', // Format the hover tooltip header as MM:SS
    },
};
</script>
